				if(arr.length==1) {
					if(arr[0] == 'users'&&localStorage.getItem('frontSessionTable')=='users') {
						return true
					}
				}
				for(let x in arr) {
					if(arr[x] == this.role) {
						return true
					}
				}
				return false
